// 計算表２（２）裏面　ページ数取得
int CTaxationList31View::GetMxList22_2_31()
{
	int		ret = 0;
	TSREC	TSrec;
	int		line_cnt = 0;
	BOOL syzSign = FALSE;
	long eymd = 0;
	if ( !( m_pSnHeadData->Sn_SKKBN % 2 ) ) {
		eymd = m_pSnHeadData->Sn_MDAYE;
	}
	else {
		eymd = m_pSnHeadData->Sn_KDAYE;
	}

	if( ( m_pSnHeadData->SVmzsw == 1 ) || ( eymd < R03YEAR ) ) {
		syzSign = TRUE;
	}

	if( m_pSpcListData->TsTbl.tp_rnum ){

		for(int rec_cnt = 0; rec_cnt < m_pSpcListData->TsTbl.tp_rnum; rec_cnt++ ){

			if( m_pSpcListData->m_TblHdl.th_rget( &TSrec, &m_pSpcListData->TsTbl, rec_cnt ) ){
				return -1;
			}

			if( syzSign ) {
				if ( m_pShinSpecific22_2_31->IsNowZrtData ( &TSrec ) == FALSE ) {
					continue;
				}
			}
			else {
				if ( m_pShinSpecific22_2_31Ex->IsNowZrtData ( &TSrec ) == FALSE ) {
					continue;
				}
			}

			line_cnt++;
		}

		ret = ( line_cnt / LINES_PER_PAGE_22_2_31 );

		if( line_cnt % LINES_PER_PAGE_22_2_31 ){
			ret++;
		}
	}

	return ret;
}

// 計算表２（２）裏面　ページの先頭のレコード番号配列作成
int CTaxationList31View::MakePageManage22_2_31()
{
	TSREC	TSrec;
	int		line_cnt = 0;

	BOOL syzSign = FALSE;
	long eymd = 0;
	if ( !( m_pSnHeadData->Sn_SKKBN % 2 ) ) {
		eymd = m_pSnHeadData->Sn_MDAYE;
	}
	else {
		eymd = m_pSnHeadData->Sn_KDAYE;
	}

	if( ( m_pSnHeadData->SVmzsw == 1 ) || ( eymd < R03YEAR ) ) {
		syzSign = TRUE;
	}

	m_PageManage_22_2_31.RemoveAll();

	if( m_pSpcListData->TsTbl.tp_rnum ){

		for(int rec_cnt = 0; rec_cnt < m_pSpcListData->TsTbl.tp_rnum; rec_cnt++ ){

			if( m_pSpcListData->m_TblHdl.th_rget( &TSrec, &m_pSpcListData->TsTbl, rec_cnt ) ){
				return -1;
			}

			if( syzSign ) {
				if ( m_pShinSpecific22_2_31->IsNowZrtData ( &TSrec ) == FALSE ) {
					continue;
				}
			}
			else {
				if ( m_pShinSpecific22_2_31Ex->IsNowZrtData ( &TSrec ) == FALSE ) {
					continue;
				}
			}


			if(( line_cnt % LINES_PER_PAGE_22_2_31 ) == 0){
				m_PageManage_22_2_31.Add( rec_cnt ); //ページ先頭のレコード番号を記憶
			}

			line_cnt++;
		}
	}

	return 0;
}

